{"path": "packages/harness/src/compaction-types.test.ts", "content": "import type { ModelMessage } from "ai";
import { describe, expect, it } from "vitest";
import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types";

// Helper function to create a minimal ModelMessage
function createModelMessage(
  role: "user" | "assistant" | "system" | "tool" = "user",
  content: string = "test content"
): ModelMessage {
  return { role, content } as ModelMessage;
}

// Helper function to create a minimal Message
function createMessage(id: string = "msg_1"): Message {
  return {
    createdAt: new Date("2024-01-01T00:00:00Z"),
    id,
    modelMessage: createModelMessage(),
  };
}

// Helper function to create a minimal CheckpointMessage
function createCheckpointMessage(id: string = "ckpt_1"): CheckpointMessage {
  return {
    createdAt: Date.now(),
    id,
    isSummary: false,
    message: createModelMessage(),
  };
}

// Helper function to create a minimal CompactionSummary
function createCompactionSummary(id: string = "summary_1"): CompactionSummary {
  return {
    createdAt: new Date("2024-01-01T00:00:00Z"),
    firstKeptMessageId: "msg_1",
    id,
    summary: "Test summary",
    summaryTokens: 100,
    tokensBefore: 1000,
  };
}

// Helper function to create a minimal CompactionSegment
function createCompactionSegment(id: string = "segment_1"): CompactionSegment {
  return {
    createdAt: new Date("2024-01-01T00:00:00Z"),
    endMessageId: "msg_10",
    estimatedTokens: 500,
    id,
    messageCount: 10,
    messageIds: ["msg_1", "msg_2"],
    messages: [createMessage()],
    startMessageId: "msg_1",
    summary: null,
  };
}

// Helper function to create a minimal PreparedCompactionSegment
function createPreparedCompactionSegment(
  id: string = "psegment_1"
): PreparedCompactionSegment {
  return {
    createdAt: new Date("2024-01-01T00:00:00Z"),
    endMessageId: "msg_10",
    estimatedTokens: 500,
    id,
    messageCount: 10,
    messageIds: ["msg_1", "msg_2"],
    messages: [createMessage()],
    startMessageId: "msg_1",
    summary: null,
  };
}

// ============================================================
// Message Interface Tests
// ============================================================
describe("Message", () => {
  it("accepts valid Message with all required fields", () => {
    const message: Message = {
      createdAt: new Date("2024-01-01T00:00:00Z"),
      id: "msg_123",
      modelMessage: createModelMessage("user", "Hello"),
    };
    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.id).toBe("msg_123");
    expect(message.modelMessage.role).toBe("user");
  });

  it("accepts Message with optional originalContent", () => {
    const message: Message = {
      createdAt: new Date(),
      id: "msg_1",
      modelMessage: createModelMessage(),
      originalContent: "Original text before edit",
    };
    expect(message.originalContent).toBe("Original text before edit");
  });

  it("accepts Message without optional originalContent", () => {
    const message: Message = {
      createdAt: new Date(),
      id: "msg_1",
      modelMessage: createModelMessage(),
    };
    expect(message.originalContent).toBeUndefined();
  });

  it("createdAt field must be Date type", () => {
    const message: Message = createMessage();
    expect(typeof message.createdAt.getTime()).toBe("number");
  });

  it("id field must be string type", () => {
    const message: Message = createMessage();
    expect(typeof message.id).toBe("string");
  });
});

// ============================================================
// CheckpointMessage Interface Tests
// ============================================================
describe("CheckpointMessage", () => {
  it("accepts valid CheckpointMessage with all required fields", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: 1704067200000,
      id: "ckpt_abc123",
      isSummary: true,
      message: createModelMessage("assistant", "Summary content"),
    };
    expect(checkpoint.createdAt).toBe(1704067200000);
    expect(checkpoint.id).toBe("ckpt_abc123");
    expect(checkpoint.isSummary).toBe(true);
  });

  it("createdAt is number (Date.now() format)", () => {
    const checkpoint = createCheckpointMessage();
    expect(typeof checkpoint.createdAt).toBe("number");
    expect(checkpoint.createdAt).toBeGreaterThan(0);
  });

  it("isSummary can be true", () => {
    const checkpoint: CheckpointMessage = {
      ...createCheckpointMessage(),
      isSummary: true,
    };
    expect(checkpoint.isSummary).toBe(true);
  });

  it("isSummary can be false", () => {
    const checkpoint: CheckpointMessage = {
      ...createCheckpointMessage(),
      isSummary: false,
    };
    expect(checkpoint.isSummary).toBe(false);
  });

  it("accepts optional originalContent", () => {
    const checkpoint: CheckpointMessage = {
      ...createCheckpointMessage(),
      originalContent: "Before rewrite",
    };
    expect(checkpoint.originalContent).toBe("Before rewrite");
  });

  it("works without optional originalContent", () => {
    const checkpoint = createCheckpointMessage();
    expect(checkpoint.originalContent).toBeUndefined();
  });
});

// ============================================================
// SessionMetadata Interface Tests
// ============================================================
describe("SessionMetadata", () => {
  it("accepts valid SessionMetadata with all required fields", () => {
    const metadata: SessionMetadata = {
      completionTokens: 500,
      createdAt: 1704067200000,
      promptTokens: 1500,
      sessionId: "session_xyz",
      summaryMessageId: "summary_1",
      updatedAt: 1704067300000,
    };
    expect(metadata.completionTokens).toBe(500);
    expect(metadata.promptTokens).toBe(1500);
    expect(metadata.sessionId).toBe("session_xyz");
  });

  it("summaryMessageId can be string", () => {
    const metadata: SessionMetadata = {
      completionTokens: 0,
      createdAt: Date.now(),
      promptTokens: 0,
      sessionId: "session_1",
      summaryMessageId: "summary_abc",
      updatedAt: Date.now(),
    };
    expect(metadata.summaryMessageId).toBe("summary_abc");
  });

  it("summaryMessageId can be null (no compaction yet)", () => {
    const metadata: SessionMetadata = {
      completionTokens: 0,
      createdAt: Date.now(),
      promptTokens: 0,
      sessionId: "session_1",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };
    expect(metadata.summaryMessageId).toBeNull();
  });

  it("all numeric fields are numbers", () => {
    const metadata: SessionMetadata = {
      completionTokens: 100,
      createdAt: 1704067200000,
      promptTokens: 200,
      sessionId: "session_1",
      summaryMessageId: null,
      updatedAt: 1704067300000,
    };
    expect(typeof metadata.completionTokens).toBe("number");
    expect(typeof metadata.createdAt).toBe("number");
    expect(typeof metadata.promptTokens).toBe("number");
    expect(typeof metadata.updatedAt).toBe("number");
  });
});

// ============================================================
// CompactionConfig Interface Tests
// ============================================================
describe("CompactionConfig", () => {
  it("accepts empty config (all fields optional)", () => {
    const config: CompactionConfig = {};
    expect(config.enabled).toBeUndefined();
    expect(config.contextLimit).toBeUndefined();
  });

  it("accepts enabled boolean", () => {
    const configEnabled: CompactionConfig = { enabled: true };
    const configDisabled: CompactionConfig = { enabled: false };
    expect(configEnabled.enabled).toBe(true);
    expect(configDisabled.enabled).toBe(false);
  });

  it("accepts contextLimit number (0 = unlimited)", () => {
    const configUnlimited: CompactionConfig = { contextLimit: 0 };
    const configLimited: CompactionConfig = { contextLimit: 128000 };
    expect(configUnlimited.contextLimit).toBe(0);
    expect(configLimited.contextLimit).toBe(128000);
  });

  it("accepts maxTokens with default documented as 8000", () => {
    const config: CompactionConfig = { maxTokens: 10000 };
    expect(config.maxTokens).toBe(10000);
  });

  it("accepts keepRecentTokens with default documented as 2000", () => {
    const config: CompactionConfig = { keepRecentTokens: 3000 };
    expect(config.keepRecentTokens).toBe(3000);
  });

  it("accepts reserveTokens with default documented as 2000", () => {
    const config: CompactionConfig = { reserveTokens: 4000 };
    expect(config.reserveTokens).toBe(4000);
  });

  it("accepts thresholdRatio with default documented as 0.5", () => {
    const config: CompactionConfig = { thresholdRatio: 0.75 };
    expect(config.thresholdRatio).toBe(0.75);
  });

  it("accepts speculativeStartRatio in valid range 0.15-0.95", () => {
    const configMin: CompactionConfig = { speculativeStartRatio: 0.15 };
    const configMax: CompactionConfig = { speculativeStartRatio: 0.95 };
    expect(configMin.speculativeStartRatio).toBe(0.15);
    expect(configMax.speculativeStartRatio).toBe(0.95);
  });

  it("accepts summarizeFn function", () => {
    const summarizeFn = async (
      messages: ModelMessage[],
      previousSummary?: string
    ): Promise<string> => {
      return `Summary of ${messages.length} messages. Previous: ${previousSummary ?? "none"}`;
    };
    const config: CompactionConfig = { summarizeFn };
    expect(config.summarizeFn).toBe(summarizeFn);
    expect(typeof config.summarizeFn).toBe("function");
  });

  it("summarizeFn receives correct parameters", async () => {
    let receivedMessages: ModelMessage[] = [];
    let receivedPrevious: string | undefined;

    const config: CompactionConfig = {
      summarizeFn: async (messages, previousSummary) => {
        receivedMessages = messages;
        receivedPrevious = previousSummary;
        return "Test summary";
      },
    };

    const messages = [createModelMessage("user", "Hello")];
    const result = await config.summarizeFn!(messages, "Previous summary");

    expect(receivedMessages).toBe(messages);
    expect(receivedPrevious).toBe("Previous summary");
    expect(result).toBe("Test summary");
  });

  it("accepts all fields together", () => {
    const config: CompactionConfig = {
      contextLimit: 100000,
      enabled: true,
      keepRecentTokens: 2500,
      maxTokens: 10000,
      reserveTokens: 3000,
      speculativeStartRatio: 0.5,
      summarizeFn: async () => "summary",
      thresholdRatio: 0.6,
    };
    expect(config.contextLimit).toBe(100000);
    expect(config.enabled).toBe(true);
    expect(config.keepRecentTokens).toBe(2500);
    expect(config.maxTokens).toBe(10000);
    expect(config.reserveTokens).toBe(3000);
    expect(config.speculativeStartRatio).toBe(0.5);
    expect(config.thresholdRatio).toBe(0.6);
  });
});

